class Solution:
    def largestPalindrome(self, n: int, k: int) -> str:
        if n == 1:
            return str(k * 9 + 4)
        max_num = int('9' * n)
        min_num = int('1' + '0' * (n - 1))
        for i in range(max_num, min_num - 1, -1):
            str_i = str(i)
            if str_i == str_i[::-1]:
                for j in range(k, 1, -1):
                    if i % j == 0:
                        quotient = i // j
                        str_j = str(quotient) + str_j
                        if str_j == str_j[::-1]:
                            return str_i
```

